import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── 1. Defensive Parser ───────── */
  const safeParseHoldings = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("DATA_CORRUPTION_ERROR", e);
      return [];
    }
  };

  /* ───────── 2. Data Actions ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Delete this strategy?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("PURGE_SUCCESSFUL");
    } catch (err) {
      toast.error("DB_LOCK_ERROR");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("PDF_SYNTHESIS_FAILED");
    }
  };

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* ── Page Header ── */}
      <div style={headerRow}>
        <div style={titleGroup}>
          <Archive size={24} color="var(--accent-primary)"/>
          <h2 style={headerStyle}>STRATEGY_VAULT</h2>
        </div>
        <span style={vaultBadge}>{history.length} NODES_STORED</span>
      </div>
      
      {/* ── Strategy List ── */}
      {history.length === 0 ? (
        <div style={emptyStyle}>NO_DATA_FOUND: INITIALIZE_STRATEGY_CORE</div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} className="vault-card" style={cardStyle}>
              <div style={cardContent}>
                <div style={tagRow}>
                  <span style={metaText}><Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={riskTag}><ShieldCheck size={14}/> RISK: {item.risk_score}</span>
                </div>
                
                <h4 style={titleStyle}>{item.goal}</h4>
                
                <div style={tickerRow}>
                   {safeParseHoldings(item.holdings).map((t, i) => (
                     <span key={i} style={tickerTag}>{t}</span>
                   ))}
                </div>
              </div>

              <div style={actionColumn}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View Description"><Eye size={20}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Download PDF"><Download size={20}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Purge Record"><Trash2 size={20}/></button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── Detail Modal (Pure Black in Dark Mode) ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader(isDark)}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={24}/></button>
            </div>
            
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              
              <div style={modalSection}>
                <p style={modalLabel}><AlignLeft size={14}/> STRATEGIC_SUMMARY</p>
                <div className="markdown-vault">
                  <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                </div>
              </div>

              <div style={modalSection}>
                <p style={modalLabel}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
                <div className="markdown-vault">
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .vault-card { transition: all 0.2s ease; background: var(--bg-input); }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-2px); }
        .markdown-vault p { color: var(--text-primary); font-size: 0.95rem; line-height: 1.6; margin-bottom: 1rem; }
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 1.1rem; margin-bottom: 0.5rem; text-transform: uppercase; }
        .reveal-node { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

